import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Helper function to map weather conditions to icon names
function getWeatherIcon(condition: string): string {
  const conditionLower = condition.toLowerCase();
  if (conditionLower.includes('sun')) return 'sun';
  if (conditionLower.includes('cloud')) return 'cloud';
  if (conditionLower.includes('rain')) return 'cloud-rain';
  if (conditionLower.includes('snow')) return 'cloud-snow';
  if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return 'cloud-lightning';
  if (conditionLower.includes('wind')) return 'wind';
  if (conditionLower.includes('fog') || conditionLower.includes('mist')) return 'cloud-fog';
  return 'cloud';
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main Weather Card */}
        <Card shadow="lg" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-4)" align="center">
            {/* City Header */}
            <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>

            {/* Weather Icon & Condition */}
            <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
              <Icon name={props.condition} size={64} color="var(--ggui-color-primary-600)" aria-label={`${props.condition} weather`} />
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
            </Stack>

            {/* Large Temperature Display */}
            <Box>
              <Heading level={1} align="center" color="var(--ggui-color-primary-600)">
                {props.temperature}°{props.unit}
              </Heading>
            </Box>

            {/* Humidity & Wind Speed */}
            <Row gap="var(--ggui-spacing-6)" justify="center" align="center">
              <Stack gap="var(--ggui-spacing-1)" align="center">
                <Icon name="droplets" size={20} color="var(--ggui-color-primary-500)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                <Text variant="body" color="var(--ggui-color-onSurface)" weight="semibold">{props.humidity}%</Text>
              </Stack>

              <Divider orientation="vertical" margin="var(--ggui-spacing-3)" />

              <Stack gap="var(--ggui-spacing-1)" align="center">
                <Icon name="wind" size={20} color="var(--ggui-color-primary-500)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                <Text variant="body" color="var(--ggui-color-onSurface)" weight="semibold">{props.windSpeed} m/s</Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast Strip */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={4} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
          <Row gap="var(--ggui-spacing-3)" wrap align="stretch">
            {props.forecast && props.forecast.length > 0 ? (
              props.forecast.map((day, index) => (
                <Card key={index} shadow="sm" padding="var(--ggui-spacing-4)" radius="md" style={{ flex: '1 1 120px', minWidth: '100px' }}>
                  <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                    {/* Day Name */}
                    {day.day && (
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" align="center">{day.day}</Text>
                    )}

                    {/* Weather Icon */}
                    {day.icon && (
                      <Icon name={day.icon} size={32} color="var(--ggui-color-primary-500)" aria-label={day.icon} />
                    )}

                    {/* High/Low Temps */}
                    <Row gap="var(--ggui-spacing-2)" justify="center">
                      {day.high !== undefined && (
                        <Text variant="body" color="var(--ggui-color-onSurface)" weight="semibold">{day.high}°</Text>
                      )}
                      {day.low !== undefined && (
                        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{day.low}°</Text>
                      )}
                    </Row>
                  </Stack>
                </Card>
              ))
            ) : (
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">No forecast data available</Text>
            )}
          </Row>
        </Stack>
      </Stack>
    </Container>
  );
}

