// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for multi-step form
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Email regex pattern
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  // Validate name - required
  const isNameValid = name.trim().length > 0;

  // Validate email - required and valid format
  const isEmailValid = email.trim().length > 0 && emailRegex.test(email);

  // Step 1 validation
  const isStep1Valid = isNameValid && isEmailValid;

  // Step 2 validation - satisfaction must be selected
  const isStep2Valid = satisfaction !== '';

  // Step 3 validation - at least one feature should be selected (optional but good UX)
  // Step 4 validation - comments are optional

  // Handle next button
  const handleNext = () => {
    if (currentStep === 1) {
      // Validate step 1
      setNameError(isNameValid ? '' : 'Name is required');
      setEmailError(isEmailValid ? '' : 'Valid email is required');
      if (isStep1Valid) {
        setCurrentStep(2);
      }
    } else if (currentStep === 2) {
      // Validate step 2
      if (isStep2Valid) {
        setCurrentStep(3);
      }
    } else if (currentStep === 3) {
      // Move to step 4 (comments)
      setCurrentStep(4);
    } else if (currentStep === 4) {
      // Move to step 5 (final review)
      setCurrentStep(5);
    } else if (currentStep === 5) {
      // Submit the form
      submit({
        name: name.trim(),
        email: email.trim(),
        satisfaction: parseInt(satisfaction),
        features,
        comments: comments.trim(),
      });
    }
  };

  // Handle back button
  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  // Handle feature checkbox change
  const handleFeatureToggle = (feature: string) => {
    if (features.includes(feature)) {
      setFeatures(features.filter(f => f !== feature));
    } else {
      setFeatures([...features, feature]);
    }
  };

  // Determine if Next button should be disabled
  const isNextDisabled = 
    (currentStep === 1 && !isStep1Valid) ||
    (currentStep === 2 && !isStep2Valid);

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header with progress */}
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={2}>Multi-Step Survey</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep} of 4
          </Text>
          <Progress value={currentStep} max={4} variant="default" size="md" aria-label={`Progress: Step ${currentStep} of 4`} />
        </Stack>

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Name"
                placeholder="Enter your full name"
                value={name}
                onChange={setName}
                error={nameError}
                required
              />
              <Input
                label="Email"
                type="email"
                placeholder="Enter your email address"
                value={email}
                onChange={setEmail}
                error={emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={satisfaction}
                onChange={setSatisfaction}
                direction="vertical"
                options={props.satisfactionLabels.map((label, index) => ({
                  value: String(index + 1),
                  label: label,
                }))}
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Features Interested In</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Select the features you are interested in
              </Text>
              <Stack gap="var(--ggui-spacing-2)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                placeholder="Share any additional thoughts or feedback..."
                value={comments}
                onChange={setComments}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Final Review (after step 4) */}
        {currentStep === 5 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap="var(--ggui-spacing-3)">
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="label" color="var(--ggui-color-primary-900)">Name</Text>
                    <Text color="var(--ggui-color-onSurface)">{name}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="label" color="var(--ggui-color-primary-900)">Email</Text>
                    <Text color="var(--ggui-color-onSurface)">{email}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="label" color="var(--ggui-color-primary-900)">Satisfaction</Text>
                    <Text color="var(--ggui-color-onSurface)">{satisfaction && props.satisfactionLabels[parseInt(satisfaction) - 1] ? props.satisfactionLabels[parseInt(satisfaction) - 1] : 'Not selected'}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="label" color="var(--ggui-color-primary-900)">Features Interested In</Text>
                    <Text color="var(--ggui-color-onSurface)">{features.length > 0 ? features.join(', ') : 'None selected'}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="label" color="var(--ggui-color-primary-900)">Comments</Text>
                    <Text color="var(--ggui-color-onSurface)">{comments || 'No comments'}</Text>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Button
            variant="primary"
            onClick={handleNext}
            disabled={isNextDisabled}
          >
            {currentStep === 4 ? 'Review' : currentStep === 5 ? 'Submit' : 'Next'}
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Helper sub-component for individual task card
function TaskCard({ task, onMove, onEdit, columns }: { task: typeof task; onMove: (taskId: string, columnId: string) => void; onEdit: (taskId: string, title: string) => void; columns: Props['columns'] }) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');
  const priorityColorMap = {
    low: 'success',
    medium: 'warning',
    high: 'error',
  } as const;

  const handleSaveEdit = () => {
    if (editTitle.trim()) {
      onEdit(task.id || '', editTitle);
      setIsEditing(false);
    }
  };

  const handleDoubleClick = () => {
    setIsEditing(true);
  };

  if (isEditing) {
    return (
      <Card padding="var(--ggui-spacing-3)" shadow="sm">
        <Stack gap="var(--ggui-spacing-2)">
          <Input
            label="Task title"
            value={editTitle}
            onChange={setEditTitle}
            placeholder="Enter task title"
          />
          <Row gap="var(--ggui-spacing-2)" justify="end">
            <Button variant="ghost" size="sm" onClick={() => setIsEditing(false)}>
              Cancel
            </Button>
            <Button variant="primary" size="sm" onClick={handleSaveEdit}>
              Save
            </Button>
          </Row>
        </Stack>
      </Card>
    );
  }

  return (
    <Card
      padding="var(--ggui-spacing-3)"
      shadow="sm"
      as={Clickable}
      onClick={handleDoubleClick}
      hoverStyle={{ opacity: 0.9 }}
    >
      <Stack gap="var(--ggui-spacing-2)">
        <Row justify="between" align="center">
          <Text variant="bodySmall" weight="semibold" style={{ flex: 1 }}>
            {task.title}
          </Text>
          <Badge variant={priorityColorMap[task.priority as keyof typeof priorityColorMap] || 'default'} size="sm">
            {task.priority}
          </Badge>
        </Row>
        <Row justify="between" align="center" gap="var(--ggui-spacing-2)">
          <Row gap="var(--ggui-spacing-1)" align="center">
            {task.assignee && <Avatar name={task.assignee} size="sm" />}
            {task.dueDate && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {new Date(task.dueDate).toLocaleDateString()}
              </Text>
            )}
          </Row>
          <Dropdown
            trigger={<Button variant="ghost" size="xs"><Icon name="move" size={14} /></Button>}
            options={columns.map((col) => ({
              value: col.id || '',
              label: col.name || '',
              disabled: col.id === task.column,
            }))}
            value={task.column || ''}
            onChange={(columnId) => onMove(task.id || '', columnId)}
            placement="bottom-end"
          />
        </Row>
      </Stack>
    </Card>
  );
}

// Helper sub-component for column
function TaskColumn({
  column,
  tasks,
  onMove,
  onEdit,
  onAddTask,
  columns,
}: {
  column: Props['columns'][0];
  tasks: Props['tasks'];
  onMove: (taskId: string, columnId: string) => void;
  onEdit: (taskId: string, title: string) => void;
  onAddTask: (columnId: string, title: string, priority: string) => void;
  columns: Props['columns'];
}) {
  const [showAddForm, setShowAddForm] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState('medium');

  const columnTasks = tasks.filter((t) => t.column === column.id);

  const handleAddTask = () => {
    if (newTitle.trim()) {
      onAddTask(column.id || '', newTitle, newPriority);
      setNewTitle('');
      setNewPriority('medium');
      setShowAddForm(false);
    }
  };

  return (
    <Stack gap="var(--ggui-spacing-3)" style={{ flex: 1, minWidth: '300px' }}>
      <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
        <Row justify="between" align="center">
          <Heading level={3}>{column.name}</Heading>
          <Badge variant="default" size="sm">
            {columnTasks.length}
          </Badge>
        </Row>
      </Box>

      <Stack gap="var(--ggui-spacing-2)" style={{ flex: 1 }}>
        {columnTasks.map((task) => (
          <TaskCard
            key={task.id}
            task={task}
            onMove={onMove}
            onEdit={onEdit}
            columns={columns}
          />
        ))}
      </Stack>

      {showAddForm ? (
        <Card padding="var(--ggui-spacing-3)" shadow="sm">
          <Stack gap="var(--ggui-spacing-2)">
            <Input
              label="Task title"
              value={newTitle}
              onChange={setNewTitle}
              placeholder="Enter new task"
            />
            <Select
              label="Priority"
              value={newPriority}
              onChange={setNewPriority}
              options={[
                { value: 'low', label: 'Low' },
                { value: 'medium', label: 'Medium' },
                { value: 'high', label: 'High' },
              ]}
            />
            <Row gap="var(--ggui-spacing-2)" justify="end">
              <Button variant="ghost" size="sm" onClick={() => setShowAddForm(false)}>
                Cancel
              </Button>
              <Button variant="primary" size="sm" onClick={handleAddTask}>
                Add Task
              </Button>
            </Row>
          </Stack>
        </Card>
      ) : (
        <Button
          variant="outline"
          size="sm"
          fullWidth
          onClick={() => setShowAddForm(true)}
        >
          + Add Task
        </Button>
      )}
    </Stack>
  );
}

export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // State for local tasks (initialized from props, updated by stream)
  const [localTasks, setLocalTasks] = useState(props.tasks);

  // Update local tasks when stream events arrive
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      setLocalTasks((prev) => {
        if (action === 'create' && task) {
          return [...prev, task];
        }
        if (action === 'move' || action === 'edit') {
          return prev.map((t) => (t.id === task?.id ? task : t));
        }
        if (action === 'delete' && task?.id) {
          return prev.filter((t) => t.id !== task.id);
        }
        return prev;
      });
    }
  }, [taskChanged.latest]);

  // Compute totals
  const totalTasks = localTasks.length;
  const completedTasks = localTasks.filter((t) => t.column === 'done').length;

  // Handlers
  const handleMoveTask = useCallback(
    (taskId: string, columnId: string) => {
      setLocalTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, column: columnId } : t))
      );
      taskUpdate({ action: 'move', taskId, data: { column: columnId } });
    },
    [taskUpdate]
  );

  const handleEditTask = useCallback(
    (taskId: string, title: string) => {
      setLocalTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, title } : t))
      );
      taskUpdate({ action: 'edit', taskId, data: { column: '' } });
    },
    [taskUpdate]
  );

  const handleAddTask = useCallback(
    (columnId: string, title: string, priority: string) => {
      const newTaskId = `task-${Date.now()}`;
      const newTask = {
        id: newTaskId,
        title,
        priority: priority as 'low' | 'medium' | 'high',
        column: columnId,
      };
      setLocalTasks((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newTaskId, data: { column: columnId } });
    },
    [taskUpdate]
  );

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Box
          padding="var(--ggui-spacing-4)"
          background="var(--ggui-color-primary-50)"
          borderRadius="var(--ggui-shape-radius-lg)"
        >
          <Row justify="between" align="center">
            <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center">
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Text variant="label" color="var(--ggui-color-primary-700)">
                  Total Tasks:
                </Text>
                <Heading
                  level={3}
                  color="var(--ggui-color-primary-700)"
                >
                  {totalTasks}
                </Heading>
              </Stack>
              <Divider orientation="vertical" margin="var(--ggui-spacing-1)" />
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Text variant="label" color="var(--ggui-color-primary-700)">
                  Completed:
                </Text>
                <Heading
                  level={3}
                  color="var(--ggui-color-success-600)"
                >
                  {completedTasks}
                </Heading>
              </Stack>
            </Stack>
            <Progress
              value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0}
              max={100}
              variant="success"
              size="md"
              showLabel
            />
          </Row>
        </Box>

        {/* Kanban Board */}
        <Row
          gap="var(--ggui-spacing-4)"
          align="start"
          wrap
          style={{ minHeight: '600px' }}
        >
          {props.columns.map((column) => (
            <TaskColumn
              key={column.id}
              column={column}
              tasks={localTasks}
              onMove={handleMoveTask}
              onEdit={handleEditTask}
              onAddTask={handleAddTask}
              columns={props.columns}
            />
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

