// Helper function to get category color using design tokens
const getCategoryColor = (category: string | undefined): string => {
  const categoryColors: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-primary-100)',
    'alkaline earth metal': 'var(--ggui-color-info-100)',
    'lanthanide': 'var(--ggui-color-success-100)',
    'actinide': 'var(--ggui-color-warning-100)',
    'transition metal': 'var(--ggui-color-error-100)',
    'post-transition metal': 'var(--ggui-color-primary-50)',
    'metalloid': 'var(--ggui-color-info-50)',
    'nonmetal': 'var(--ggui-color-success-50)',
    'halogen': 'var(--ggui-color-warning-50)',
    'noble gas': 'var(--ggui-color-error-50)',
  };
  return categoryColors[category?.toLowerCase() || ''] || 'var(--ggui-color-surfaceVariant)';
};

// Helper function to get category text color
const getCategoryTextColor = (category: string | undefined): string => {
  const categoryTextColors: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-primary-700)',
    'alkaline earth metal': 'var(--ggui-color-info-700)',
    'lanthanide': 'var(--ggui-color-success-700)',
    'actinide': 'var(--ggui-color-warning-700)',
    'transition metal': 'var(--ggui-color-error-700)',
    'post-transition metal': 'var(--ggui-color-primary-700)',
    'metalloid': 'var(--ggui-color-info-700)',
    'nonmetal': 'var(--ggui-color-success-700)',
    'halogen': 'var(--ggui-color-warning-700)',
    'noble gas': 'var(--ggui-color-error-700)',
  };
  return categoryTextColors[category?.toLowerCase() || ''] || 'var(--ggui-color-onSurfaceVariant)';
};

export default function Component(props: Props) {
  // State for search and detail panel
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<(typeof props.elements)[0] | null>(null);

  // Filter elements based on search query (by name or symbol)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el =>
      el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query)
    );
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach(el => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-3)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Interactive periodic table. Click on an element to view details.
          </Text>
        </Stack>

        {/* Search Input */}
        <SearchField
          value={searchQuery}
          onChange={setSearchQuery}
          placeholder="Search by element name or symbol..."
          size="md"
        />

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-2)">
            <Text variant="label" weight="semibold">Legend</Text>
            <Row gap="var(--ggui-spacing-4)" wrap={true} align="center">
              {categories.map(cat => (
                <Row key={cat} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    padding="var(--ggui-spacing-2)"
                    background={getCategoryColor(cat)}
                    borderRadius="var(--ggui-shape-radius-sm)"
                    style={{ minWidth: '24px', minHeight: '24px' }}
                  />
                  <Text variant="bodySmall">{cat}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, 1fr)',
          gap: 'var(--ggui-spacing-2)',
          padding: 'var(--ggui-spacing-4)',
          background: 'var(--ggui-color-surface)',
          borderRadius: 'var(--ggui-shape-radius-lg)',
          border: '1px solid var(--ggui-color-outlineVariant)',
        }}>
          {filteredElements.map(element => {
            if (!element.row || !element.col) return null;
            return (
              <Card
                key={element.symbol}
                as={Clickable}
                onClick={() => setSelectedElement(element)}
                padding="var(--ggui-spacing-2)"
                shadow="sm"
                style={{
                  gridRow: element.row,
                  gridColumn: element.col,
                  background: getCategoryColor(element.category),
                  cursor: 'pointer',
                  minHeight: '60px',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'center',
                  alignItems: 'center',
                  textAlign: 'center',
                  transition: 'all 200ms ease-in-out',
                  border: selectedElement?.symbol === element.symbol
                    ? '2px solid var(--ggui-color-primary-600)'
                    : '1px solid var(--ggui-color-outlineVariant)',
                }}
                hoverStyle={{
                  opacity: 0.85,
                  boxShadow: 'var(--ggui-shape-shadow-md)',
                }}
              >
                <Text
                  variant="caption"
                  color={getCategoryTextColor(element.category)}
                  style={{ fontSize: '10px', lineHeight: '1' }}
                >
                  {element.atomicNumber}
                </Text>
                <Text
                  variant="label"
                  weight="bold"
                  color={getCategoryTextColor(element.category)}
                  style={{ fontSize: '18px', lineHeight: '1.2' }}
                >
                  {element.symbol}
                </Text>
                <Text
                  variant="caption"
                  color={getCategoryTextColor(element.category)}
                  style={{ fontSize: '9px', lineHeight: '1' }}
                >
                  {element.atomicWeight?.toFixed(2)}
                </Text>
              </Card>
            );
          })}
        </div>

        {/* Detail Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Row justify="between" align="center">
                <Heading level={2}>{selectedElement.name}</Heading>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedElement(null)}
                >
                  ✕
                </Button>
              </Row>
              <Divider orientation="horizontal" margin="0" />
              <Row justify="between" gap="var(--ggui-spacing-6)" wrap={true}>
                <Stack gap="var(--ggui-spacing-3)">
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Symbol</Text>
                    <Heading level={4}>{selectedElement.symbol}</Heading>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Atomic Number</Text>
                    <Text variant="bodyLarge" weight="semibold">{selectedElement.atomicNumber}</Text>
                  </Stack>
                </Stack>
                <Stack gap="var(--ggui-spacing-3)">
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                    <Text variant="bodyLarge" weight="semibold">{selectedElement.atomicWeight?.toFixed(4)}</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Category</Text>
                    <Badge variant="primary">{selectedElement.category}</Badge>
                  </Stack>
                </Stack>
              </Row>
            </Stack>
          </Card>
        )}

        {/* No Results Message */}
        {filteredElements.length === 0 && (
          <Alert variant="info" title="No elements found">
            Try adjusting your search query to find elements by name or symbol.
          </Alert>
        )}
      </Stack>
    </Container>
  );
}

