// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Computed values
  const stock = props.product.stock ?? 0;
  const isOutOfStock = stock === 0;
  const isLowStock = stock > 0 && stock < 10;
  const rating = props.product.rating ?? 0;
  const reviewCount = props.product.reviewCount ?? 0;
  const price = props.product.price ?? 0;
  const currency = props.product.currency ?? '$';

  // Handlers
  const handleQuantityIncrease = useCallback(() => {
    setQuantity((prev) => (prev < stock ? prev + 1 : prev));
  }, [stock]);

  const handleQuantityDecrease = useCallback(() => {
    setQuantity((prev) => (prev > 1 ? prev - 1 : 1));
  }, []);

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  // Helper: render star rating
  const renderStars = (value: number) => {
    return (
      <Row gap="var(--ggui-spacing-1)" align="center">
        {Array.from({ length: 5 }).map((_, i) => (
          <Icon
            key={i}
            name="star"
            size={16}
            color={i < Math.round(value) ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
          />
        ))}
        {reviewCount > 0 && (
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" is="span">
            ({reviewCount})
          </Text>
        )}
      </Row>
    );
  };

  // Helper: format price
  const formattedPrice = `${currency}${price.toFixed(2)}`;

  // Tab items
  const tabItems = useMemo(() => [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Text color="var(--ggui-color-onSurface)">{props.product.description || 'No description available'}</Text>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: Array.isArray(props.product.specifications) && props.product.specifications.length > 0 ? (
        <Table
          columns={[
            { key: 'key', header: 'Feature', width: '40%' },
            { key: 'value', header: 'Value', width: '60%' },
          ]}
          data={props.product.specifications as Record<string, unknown>[]}
          striped
        />
      ) : (
        <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available</Text>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: Array.isArray(props.product.reviews) && props.product.reviews.length > 0 ? (
        <Stack gap="var(--ggui-spacing-4)">
          {(props.product.reviews as any[]).map((review: any, idx: number) => (
            <Card key={idx} padding="var(--ggui-spacing-4)" shadow="sm">
              <Stack gap="var(--ggui-spacing-2)">
                <Row gap="var(--ggui-spacing-2)" align="center">
                  <Text variant="label" color="var(--ggui-color-onSurface)" weight="semibold">{review.author || 'Anonymous'}</Text>
                  {renderStars(review.rating || 0)}
                </Row>
                <Text color="var(--ggui-color-onSurface)">{review.text || review.content || ''}</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{review.date ? new Date(review.date).toLocaleDateString() : ''}</Text>
              </Stack>
            </Card>
          ))}
        </Stack>
      ) : (
        <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet</Text>
      ),
    },
  ], [props.product.description, props.product.specifications, props.product.reviews]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* TOP SECTION: Image + Product Details */}
        <Stack gap="var(--ggui-spacing-6)" direction="horizontal" style={{ flexWrap: 'wrap', alignItems: 'flex-start' }}>
          <Box
            padding="var(--ggui-spacing-4)"
            background="var(--ggui-color-primary-100)"
            borderRadius="var(--ggui-shape-radius-lg)"
            style={{ minHeight: '300px', minWidth: '300px', flex: '1 1 300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Text color="var(--ggui-color-primary-700)" size="lg" weight="semibold">{props.product.name || 'Product Image'}</Text>
          </Box>
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: '1 1 300px' }}>
            <Heading level={2}>{props.product.name || 'Product Name'}</Heading>
            <Text size="lg" weight="bold" color="var(--ggui-color-primary-600)">{formattedPrice}</Text>
            <Box>
              {renderStars(rating)}
            </Box>
            <Badge variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'}>
              {isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock'}
            </Badge>
          </Stack>
        </Stack>

        {/* MIDDLE SECTION: Tabs */}
        <Tabs
          items={tabItems}
          activeKey={activeTab}
          onChange={setActiveTab}
          variant="line"
          size="md"
        />

        {/* BOTTOM SECTION: Quantity Selector and Add to Cart */}
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            {/* Quantity Selector */}
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="label" color="var(--ggui-color-onSurface)">Quantity</Text>
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Button
                  variant="outline"
                  size="md"
                  onClick={handleQuantityDecrease}
                  disabled={quantity <= 1}
                >
                  −
                </Button>
                <Box
                  padding="var(--ggui-spacing-2)"
                  style={{
                    minWidth: '60px',
                    textAlign: 'center',
                    fontWeight: 'var(--ggui-font-weight-medium)',
                  }}
                >
                  <Text color="var(--ggui-color-onSurface)">{quantity}</Text>
                </Box>
                <Button
                  variant="outline"
                  size="md"
                  onClick={handleQuantityIncrease}
                  disabled={quantity >= stock}
                >
                  +
                </Button>
              </Stack>
              {stock > 0 && (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {stock} available
                </Text>
              )}
            </Stack>

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="lg"
              fullWidth
              onClick={handleAddToCart}
              disabled={isOutOfStock}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
}

