/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [messages, setMessages] = useState(props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const [typingIndicators, setTypingIndicators] = useState<Record<string, boolean>>({});
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator from stream
  useEffect(() => {
    if (typing.latest) {
      const { sender, active } = typing.latest;
      if (sender) {
        setTypingIndicators((prev) => ({
          ...prev,
          [sender]: active ?? false,
        }));
      }
    }
  }, [typing.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      sendMessage({
        text: inputValue,
        timestamp: new Date().toISOString(),
      });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  // Handle Enter key
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Compute active typing senders (excluding current user)
  const activeTypers = useMemo(() => {
    return Object.entries(typingIndicators)
      .filter(([_, isTyping]) => isTyping)
      .map(([sender]) => sender)
      .filter((sender) => sender !== props.currentUser);
  }, [typingIndicators, props.currentUser]);

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    return messages.reduce((acc, msg, idx) => {
      const prevMsg = messages[idx - 1];
      const isSameSender = prevMsg && prevMsg.sender === msg.sender;

      if (isSameSender) {
        acc[acc.length - 1].messages.push(msg);
      } else {
        acc.push({ sender: msg.sender || 'Unknown', messages: [msg] });
      }
      return acc;
    }, [] as Array<{ sender: string; messages: typeof messages }>);
  }, [messages]);

  return (
    <Card
      shadow="lg"
      padding="var(--ggui-spacing-4)"
      radius="lg"
      border={true}
      style={{ height: '100vh', display: 'flex', flexDirection: 'column' }}
    >
      {/* Header */}
      <Stack direction="horizontal" align="center" justify="between" gap="var(--ggui-spacing-4)" style={{ paddingBottom: 'var(--ggui-spacing-4)', borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2)">
          <Heading level={3} color="var(--ggui-color-onSurface)">
            {props.title}
          </Heading>
        </Stack>
        <Badge variant="primary" size="sm">
          {props.participantCount} {props.participantCount === 1 ? 'participant' : 'participants'}
        </Badge>
      </Stack>

      {/* Messages List */}
      <Stack
        gap="var(--ggui-spacing-3)"
        style={{
          flex: 1,
          overflowY: 'auto',
          paddingTop: 'var(--ggui-spacing-4)',
          paddingBottom: 'var(--ggui-spacing-4)',
        }}
      >
        {groupedMessages.length === 0 ? (
          <Box style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
            <Text color="var(--ggui-color-onSurfaceVariant)" align="center">
              No messages yet. Start the conversation!
            </Text>
          </Box>
        ) : (
          <>
            {groupedMessages.map((group, idx) => {
              const isCurrentUser = group.sender === props.currentUser;
              return (
                <Stack
                  key={idx}
                  align={isCurrentUser ? 'end' : 'start'}
                  gap="var(--ggui-spacing-1)"
                  style={{
                    marginLeft: isCurrentUser ? 'auto' : 0,
                    marginRight: isCurrentUser ? 0 : 'auto',
                  }}
                >
                  {/* Show sender name only for grouped messages from others */}
                  {!isCurrentUser && (
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      {group.sender}
                    </Text>
                  )}
                  {/* Message bubbles */}
                  <Stack gap="var(--ggui-spacing-2)">
                    {group.messages.map((msg, msgIdx) => (
                      <Card
                        key={msgIdx}
                        padding="var(--ggui-spacing-3)"
                        radius="md"
                        border={false}
                        shadow="sm"
                        style={{
                          background: isCurrentUser
                            ? 'var(--ggui-color-primary-600)'
                            : 'var(--ggui-color-surfaceVariant)',
                          maxWidth: '70%',
                        }}
                      >
                        <Stack gap="var(--ggui-spacing-1)">
                          <Text
                            color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface)'}
                            style={{ wordWrap: 'break-word' }}
                          >
                            {msg.text || ''}
                          </Text>
                          <Text
                            variant="caption"
                            color={isCurrentUser ? 'rgba(255, 255, 255, 0.7)' : 'var(--ggui-color-onSurfaceVariant)'}
                          >
                            {msg.timestamp
                              ? new Date(msg.timestamp).toLocaleTimeString([], {
                                  hour: '2-digit',
                                  minute: '2-digit',
                                })
                              : ''}
                          </Text>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>
                </Stack>
              );
            })}
            <div ref={messagesEndRef} />
          </>
        )}
      </Stack>

      {/* Typing Indicator */}
      {activeTypers.length > 0 && (
        <Box
          padding="var(--ggui-spacing-2)"
          style={{
            borderTop: '1px solid var(--ggui-color-outlineVariant)',
            display: 'flex',
            alignItems: 'center',
            gap: 'var(--ggui-spacing-2)',
          }}
        >
          <Spinner size={16} color="var(--ggui-color-primary-600)" />
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            {activeTypers.slice(0, 2).join(', ')}{activeTypers.length > 2 ? ` +${activeTypers.length - 2}` : ''} typing
          </Text>
        </Box>
      )}

      {/* Input Area */}
      <Stack
        direction="horizontal"
        align="end"
        gap="var(--ggui-spacing-2)"
        style={{
          paddingTop: 'var(--ggui-spacing-4)',
          borderTop: '1px solid var(--ggui-color-outlineVariant)',
        }}
      >
        <TextArea
          label="Message"
          placeholder="Type a message.."
          value={inputValue}
          onChange={setInputValue}
          rows={2}
          disabled={false}
          style={{
            flex: 1,
          }}
          onKeyDown={handleKeyDown}
        />
        <Button
          variant="primary"
          size="md"
          onClick={handleSendMessage}
          disabled={!inputValue.trim()}
        >
          Send
        </Button>
      </Stack>
    </Card>
  );
}

