export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for displaying stocks and tracking which ones just updated
  const [displayStocks, setDisplayStocks] = useState(props.stocks || []);
  const [lastUpdateTime, setLastUpdateTime] = useState<string>('');
  const [updatedSymbols, setUpdatedSymbols] = useState<Set<string>>(new Set());
  const updateTimeoutRef = useRef<NodeJS.Timeout>();

  // Update display timestamp whenever a price update arrives
  useEffect(() => {
    if (priceUpdate.latest) {
      setLastUpdateTime(new Date().toLocaleTimeString());

      // Update the stock with new price data
      setDisplayStocks(prev => {
        const updated = prev.map(stock => {
          if (stock.symbol === priceUpdate.latest?.symbol) {
            return {
              ...stock,
              price: priceUpdate.latest.price || stock.price,
              change: priceUpdate.latest.change !== undefined ? priceUpdate.latest.change : stock.change,
              changePercent: priceUpdate.latest.changePercent !== undefined ? priceUpdate.latest.changePercent : stock.changePercent,
            };
          }
          return stock;
        });
        return updated;
      });

      // Mark this symbol as updated for animation
      setUpdatedSymbols(prev => {
        const next = new Set(prev);
        next.add(priceUpdate.latest?.symbol || '');
        return next;
      });

      // Clear the updated symbol after animation completes
      if (updateTimeoutRef.current) {
        clearTimeout(updateTimeoutRef.current);
      }
      updateTimeoutRef.current = setTimeout(() => {
        setUpdatedSymbols(new Set());
      }, 700);
    }
  }, [priceUpdate.latest]);

  // Cleanup timeout on unmount
  useEffect(() => {
    return () => {
      if (updateTimeoutRef.current) {
        clearTimeout(updateTimeoutRef.current);
      }
    };
  }, []);

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-6)">
          {/* Header */}
          <Box>
            <Row justify="between" align="center">
              <Heading level={1} color="var(--ggui-color-onSurface)">
                Market Watch
              </Heading>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated: {lastUpdateTime || 'Never'}
              </Text>
            </Row>
          </Box>

          {/* Market Status */}
          {marketStatus.latest && (
            <Box
              padding="var(--ggui-spacing-3)"
              background="var(--ggui-color-surfaceVariant)"
              borderRadius="var(--ggui-shape-radius-md)"
            >
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Market Status: <Text is="span" weight="semibold" color="var(--ggui-color-onSurface)">
                  {marketStatus.latest.status === 'open' ? '🟢 Open' : 
                   marketStatus.latest.status === 'closed' ? '🔴 Closed' : 
                   marketStatus.latest.status === 'pre-market' ? '🟡 Pre-Market' : '🟡 After-Hours'}
                </Text>
              </Text>
            </Box>
          )}

          {/* Stock Grid - Responsive using CardGrid */}
          {displayStocks && displayStocks.length > 0 ? (
            <CardGrid columns={3} gap={16}>
              {displayStocks.map((stock) => (
                <StockCard
                  key={stock.symbol}
                  stock={stock}
                  hasUpdate={updatedSymbols.has(stock.symbol || '')}
                />
              ))}
            </CardGrid>
          ) : (
            <Box
              padding="var(--ggui-spacing-8)"
              background="var(--ggui-color-surfaceVariant)"
              borderRadius="var(--ggui-shape-radius-lg)"
            >
              <Stack gap="var(--ggui-spacing-3)" align="center">
                <Icon name="inbox" size={32} color="var(--ggui-color-onSurfaceVariant)" />
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center">
                  No stocks to display
                </Text>
              </Stack>
            </Box>
          )}
