interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // State for wizard steps and form data
  const [currentStep, setCurrentStep] = useState(1);
  const [profile, setProfile] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || props.avatarOptions[0] || '',
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Validation
  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const isStep1Valid = profile.name.trim() !== '' && validateEmail(profile.email);

  const handleNext = () => {
    if (currentStep === 1) {
      const newErrors: Record<string, string> = {};
      if (!profile.name.trim()) newErrors.name = 'Name is required';
      if (!validateEmail(profile.email)) newErrors.email = 'Valid email is required';
      if (Object.keys(newErrors).length > 0) {
        setErrors(newErrors);
        return;
      }
    }
    setErrors({});
    setCurrentStep(currentStep + 1);
  };

  const handleBack = () => {
    setErrors({});
    setCurrentStep(currentStep - 1);
  };

  const handleComplete = () => {
    complete({
      name: profile.name,
      email: profile.email,
      avatar: profile.avatar,
      role: profile.role,
      emailNotifications: profile.emailNotifications,
      theme: profile.theme,
    });
  };

  const renderStepIndicator = () => (
    <Stack gap="var(--ggui-spacing-4)" align="center" style={{ marginBottom: 'var(--ggui-spacing-6)' }}>
      <Text variant="label">Step {currentStep} of 3</Text>
      <Progress value={currentStep} max={3} variant="default" size="md" />
    </Stack>
  );
  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {renderStepIndicator()}

        {currentStep === 1 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Profile Setup</Heading>
            <Input
              label="Name"
              placeholder="Enter your name"
              value={profile.name}
              onChange={(value) => setProfile({ ...profile, name: value })}
              error={errors.name}
              required
            />
            <Input
              label="Email"
              type="email"
              placeholder="you@example.com"
              value={profile.email}
              onChange={(value) => setProfile({ ...profile, email: value })}
              error={errors.email}
              required
            />
            <FormField label="Avatar" required>
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)">
                {props.avatarOptions.map((emoji) => (
                  <Box
                    key={emoji}
                    as={Clickable}
                    onClick={() => setProfile({ ...profile, avatar: emoji })}
                    padding="var(--ggui-spacing-2)"
                    borderRadius="var(--ggui-shape-radius-md)"
                    background={profile.avatar === emoji ? 'var(--ggui-color-primary-100)' : 'transparent'}
                    style={{ cursor: 'pointer', border: profile.avatar === emoji ? '2px solid var(--ggui-color-primary-600)' : '2px solid var(--ggui-color-outline)', fontSize: '32px' }}
                  >
                    {emoji}
                  </Box>
                ))}
              </Stack>
            </FormField>
          </Stack>
        )}

        {currentStep === 2 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Preferences</Heading>
            <Select
              label="Role"
              value={profile.role}
              onChange={(value) => setProfile({ ...profile, role: value })}
              options={props.roleOptions.map((role) => ({ value: role, label: role }))}
              placeholder="Select your role"
            />
            <Toggle
              label="Email Notifications"
              checked={profile.emailNotifications}
              onChange={(checked) => setProfile({ ...profile, emailNotifications: checked })}
            />
            <Toggle
              label="Dark Theme"
              checked={profile.theme === 'dark'}
              onChange={(checked) => setProfile({ ...profile, theme: checked ? 'dark' : 'light' })}
            />
          </Stack>
        )}

        {currentStep === 3 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Review & Confirm</Heading>
            <Card padding="var(--ggui-spacing-4)" shadow="md">
              <Stack gap="var(--ggui-spacing-3)">
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                  <Text>{profile.name}</Text>
                </Box>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                  <Text>{profile.email}</Text>
                </Box>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Avatar</Text>
                  <Text style={{ fontSize: '24px' }}>{profile.avatar}</Text>
                </Box>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Role</Text>
                  <Text>{profile.role}</Text>
                </Box>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email Notifications</Text>
                  <Text>{profile.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                </Box>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Theme</Text>
                  <Text>{profile.theme === 'dark' ? 'Dark' : 'Light'}</Text>
                </Box>
              </Stack>
            </Card>
          </Stack>
        )}

        {/* Navigation buttons */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-2)" justify="end">
          {currentStep > 1 && (
            <Button variant="ghost" onClick={handleBack}>
              Go Back
            </Button>
          )}
          {currentStep < 3 && (
            <Button variant="primary" onClick={handleNext} disabled={currentStep === 1 && !isStep1Valid}>
              Next
            </Button>
          )}
          {currentStep === 3 && (
            <Button variant="primary" onClick={handleComplete}>
              Complete Setup
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

