  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed
const getConditionIcon = (condition: string): string => {
  const normalized = condition.toLowerCase();
  if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('cloud') || normalized.includes('overcast')) return '☁️';
  if (normalized.includes('rain') || normalized.includes('drizzle') || normalized.includes('shower')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('blizzard')) return '❄️';
  if (normalized.includes('wind') || normalized.includes('breeze')) return '💨';
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️';
  return '🌤️';
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [selectedForecastIndex, setSelectedForecastIndex] = useState<number>(0);

  useEffect(() => {
    if (!props.forecast || props.forecast.length === 0) {
      setSelectedForecastIndex(0);
      return;
    }
    if (selectedForecastIndex > props.forecast.length - 1) {
      setSelectedForecastIndex(0);
    }
  }, [props.forecast, selectedForecastIndex]);

  const safeForecast = useMemo(() => {
    if (!props.forecast) return [];
    return props.forecast.slice(0, 5);
  }, [props.forecast]);

  const selectedForecast = useMemo(() => {
    if (safeForecast.length === 0) return null;
    return safeForecast[selectedForecastIndex] || safeForecast[0] || null;
  }, [safeForecast, selectedForecastIndex]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Box
        padding="var(--ggui-spacing-6)"
        background="var(--ggui-color-surface)"
        borderRadius="var(--ggui-shape-radius-lg)"
      >
        <Stack gap="var(--ggui-spacing-6)">
          <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
            <Stack gap="var(--ggui-spacing-4)">
              <Row justify="between" align="center">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                    Current Weather
                  </Text>
                  <Heading level={2} color="var(--ggui-color-onSurface)">
                    {props.city}
                  </Heading>
                </Stack>
                <Badge variant="primary">{props.condition}</Badge>
              </Row>

              <Row justify="between" align="center" wrap>
                <Row align="center" gap="var(--ggui-spacing-3)">
                  <Icon name={getConditionIcon(props.condition)} size={40} color="var(--ggui-color-primary-600)" />
                  <Text
                    size="4xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface)"
                  >
                    {props.temperature}°{props.unit}
                  </Text>
                </Row>
                <Stack gap="var(--ggui-spacing-1)" align="end">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Condition
                  </Text>
                  <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface)">
                    {props.condition}
                  </Text>
                </Stack>
              </Row>

              <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

              <Row gap="var(--ggui-spacing-6)" wrap>
                <Row align="center" gap="var(--ggui-spacing-2)">
                  <Icon name="droplets" size={18} color="var(--ggui-color-primary-600)" />
                  <Text variant="body" color="var(--ggui-color-onSurface)">
                    Humidity: <Text is="span" weight="semibold">{props.humidity}%</Text>
                  </Text>
                </Row>
                <Row align="center" gap="var(--ggui-spacing-2)">
                  <Icon name="wind" size={18} color="var(--ggui-color-primary-600)" />
                  <Text variant="body" color="var(--ggui-color-onSurface)">
                    Wind: <Text is="span" weight="semibold">{props.windSpeed} km/h</Text>
                  </Text>
                </Row>
              </Row>
            </Stack>
          </Card>

          <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
            <Stack gap="var(--ggui-spacing-3)">
              <Row justify="between" align="center">
                <Heading level={4} color="var(--ggui-color-onSurface)">
                  5-Day Forecast
                </Heading>
                {selectedForecast && (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    Selected: {selectedForecast.day || 'N/A'}
                  </Text>
                )}
              </Row>

              {safeForecast.length === 0 ? (
                <Alert variant="info" title="No forecast data">
                  Forecast is currently unavailable.
