                      }}
                      style={{
                        outline: selectedForecastIndex === index
                          ? '2px solid var(--ggui-color-primary-600)'
                          : '2px solid transparent',
                        outlineOffset: '2px'
                      }}
                    >
                      <Stack gap="var(--ggui-spacing-2)" align="center">
