import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touchedName, setTouchedName] = useState(false);
  const [touchedEmail, setTouchedEmail] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const safeSatisfactionLabels = Array.isArray(props.satisfactionLabels) ? props.satisfactionLabels : [];
  const safeFeatureOptions = Array.isArray(props.featureOptions) ? props.featureOptions : [];

  const nameError = touchedName && name.trim().length === 0 ? 'Name is required.' : '';
  const emailError = touchedEmail && email.trim().length === 0
    ? 'Email is required.'
    : touchedEmail && !EMAIL_REGEX.test(email.trim())
      ? 'Enter a valid email address.'
      : '';
  const commentsError = comments.length > 500 ? 'Comments cannot exceed 500 characters.' : '';

  const isStep1Valid = name.trim().length > 0 && EMAIL_REGEX.test(email.trim());
  const isStep2Valid = satisfaction !== '';
  const isStep3Valid = true;
  const isStep4Valid = comments.length <= 500;
  const totalSteps = 5;

  const canGoNext =
    (step === 1 && isStep1Valid) ||
    (step === 2 && isStep2Valid) ||
    (step === 3 && isStep3Valid) ||
    (step === 4 && isStep4Valid);

  const progressValue = (step / totalSteps) * 100;

  const satisfactionOptions = safeSatisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label,
  }));

  const toggleFeature = useCallback((option: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(option)) {
          return prev;
        }
        return [...prev, option];
      }
      return prev.filter((item) => item !== option);
    });
  }, []);

  const handleNext = useCallback(() => {
    if (step === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
      if (!isStep1Valid) {
        return;
      }
    }
    if (step === 2 && !isStep2Valid) {
      return;
    }
    if (step === 4 && !isStep4Valid) {
      return;
    }
    setStep((prev) => (prev < totalSteps ? prev + 1 : prev));
  }, [step, isStep1Valid, isStep2Valid, isStep4Valid]);

  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleSubmit = useCallback(() => {
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features,
      comments,
    };
    submit(payload);
    setSubmitted(true);
  }, [name, email, satisfaction, features, comments, submit]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" border radius="lg">
        <Stack gap="var(--ggui-spacing-5)">
          <Stack gap="var(--ggui-spacing-2)">
            <Row justify="between" align="center">
              <Heading level={3} color="var(--ggui-color-onSurface)">Survey</Heading>
              <Badge variant="primary">Step {step} of {totalSteps}</Badge>
            </Row>
            <Progress value={progressValue} max={100} variant="default" size="md" />
          </Stack>

          {submitted && (
            <Alert variant="success" title="Submitted">
              Thank you! Your survey response has been submitted.
            </Alert>
          )}

          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>About You</Heading>
              <Input
                label="Name"
                value={name}
                onChange={(value) => {
                  setName(value);
                  if (!touchedName) {
                    setTouchedName(true);
                  }
                }}
                required
                error={nameError || undefined}
                placeholder="Enter your full name"
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={(value) => {
                  setEmail(value);
                  if (!touchedEmail) {
                    setTouchedEmail(true);
                  }
                }}
                required
                error={emailError || undefined}
                placeholder="you@example.com"
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Satisfaction Rating</Heading>
              {satisfactionOptions.length === 0 ? (
                <Alert variant="warning" title="No rating labels provided">
                  Satisfaction labels are unavailable.
                </Alert>
              ) : (
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  direction="vertical"
                />
              )}
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Feature Interests</Heading>
              {safeFeatureOptions.length === 0 ? (
                <Alert variant="info" title="No features available">
                  There are currently no feature options to select.
                </Alert>
              ) : (
                <Stack gap="var(--ggui-spacing-2)">
                  {safeFeatureOptions.map((option) => (
                    <Checkbox
                      key={option}
                      label={option}
                      checked={features.includes(option)}
                      onChange={(checked) => toggleFeature(option, checked)}
                    />
                  ))}
                </Stack>
              )}
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Additional Comments</Heading>
              <TextArea
                label="Comments (optional)"
                value={comments}
                onChange={setComments}
                rows={6}
                maxLength={500}
                showCount
                placeholder="Share any additional thoughts..."
                error={commentsError || undefined}
              />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {comments.length}/500 characters
              </Text>
            </Stack>
          )}

          {step === 5 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Review Your Answers</Heading>
              <Card padding="var(--ggui-spacing-4)" border shadow="sm" radius="md">
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between"><Text variant="label">Name</Text><Text>{name || '—'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Row justify="between"><Text variant="label">Email</Text><Text>{email || '—'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Row justify="between"><Text variant="label">Satisfaction</Text><Text>{satisfaction ? (safeSatisfactionLabels[Number(satisfaction) - 1] || satisfaction) : '—'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="label">Interested Features</Text>
                    <Text color="var(--ggui-color-onSurfaceVariant)">{features.length > 0 ? features.join(', ') : 'None selected'}</Text>
                  </Stack>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="label">Comments</Text>
                    <Text color="var(--ggui-color-onSurfaceVariant)">{comments.trim().length > 0 ? comments : 'No comments provided'}</Text>
                  </Stack>
                </Stack>
              </Card>
            </Stack>
          )}

          <Divider margin="0" />
          <Row justify="between" align="center">
            <Button variant="outline" onClick={handleBack} disabled={step === 1}>
              Back
            </Button>
            {step < totalSteps ? (
              <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit} disabled={submitted}>
                {submitted ? 'Submitted' : 'Submit'}
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

