import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed
type LocalTask = { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string };
const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];
function getPriorityBadgeVariant(priority: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  return 'success';
}
function normalizeTasks(tasks: Props['tasks'], fallbackColumnId: string): LocalTask[] {
  return (tasks || []).map((task, index) => ({
    id: task.id || `task-${index}` ,
    title: task.title || 'Untitled task',
    priority: task.priority || 'medium',
    assignee: task.assignee || 'NA',
    column: task.column || fallbackColumnId,
    dueDate: task.dueDate || '',
  }));
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board
  const fallbackColumnId = useMemo(() => (props.columns && props.columns[0] && props.columns[0].id ? props.columns[0].id : 'todo'), [props.columns]);
  const [boardTasks, setBoardTasks] = useState<LocalTask[]>(() => normalizeTasks(props.tasks, fallbackColumnId));
  const [addingColumnId, setAddingColumnId] = useState<string>('');
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  useEffect(() => {
    setBoardTasks(normalizeTasks(props.tasks, fallbackColumnId));
  }, [props.tasks, fallbackColumnId]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const streamTask = taskChanged.latest.task;
    const streamId = streamTask.id || '';
    if (!streamId) return;

    if (taskChanged.latest.action === 'delete') {
      setBoardTasks((prev) => prev.filter((task) => task.id !== streamId));
      return;
    }

    setBoardTasks((prev) => {
      const existingIndex = prev.findIndex((task) => task.id === streamId);
      const mergedTask: LocalTask = {
        id: streamId,
        title: streamTask.title || 'Untitled task',
        priority: streamTask.priority || 'medium',
        assignee: streamTask.assignee || 'NA',
        column: streamTask.column || fallbackColumnId,
        dueDate: streamTask.dueDate || '',
      };

      if (existingIndex === -1) {
        return [...prev, mergedTask];
      }

      const next = [...prev];
      next[existingIndex] = { ...next[existingIndex], ...mergedTask };
      return next;
    });
  }, [taskChanged.latest, fallbackColumnId]);

  const totalTasks = boardTasks.length;
  const completedColumnId = useMemo(() => {
    const match = (props.columns || []).find((column) => (column.name || '').toLowerCase() === 'done');
    return (match && match.id) || 'done';
  }, [props.columns]);
  const completedCount = useMemo(() => boardTasks.filter((task) => task.column === completedColumnId).length, [boardTasks, completedColumnId]);

  const moveTask = useCallback(
    (taskId: string, toColumnId: string) => {
      setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: toColumnId } : task)));
      taskUpdate({ action: 'move', taskId, data: { column: toColumnId } });
    },
    [taskUpdate]
  );

  const startEditTask = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle);
  }, []);

  const saveEditTask = useCallback(
    (taskId: string) => {
      const trimmed = editingTitle.trim();
      if (!trimmed) return;
      const existingTask = boardTasks.find((task) => task.id === taskId);
      const updatedTask: LocalTask = {
        id: taskId,
        title: trimmed,
