// Place helper components here if needed
type SpecificationItem = { key: string; value: string };
type ReviewItem = { author: string; rating: number; text: string; date: string };

function normalizeSpecifications(items: unknown[] | undefined): SpecificationItem[] {
  if (!items || !Array.isArray(items)) return [];
  return items
    .map((item) => {
      if (item && typeof item === 'object') {
        const record = item as Record<string, unknown>;
        const fromKeyValue =
          typeof record.key === 'string' && typeof record.value === 'string'
            ? { key: record.key, value: record.value }
            : null;
        if (fromKeyValue) return fromKeyValue;

        const entries = Object.entries(record);
        if (entries.length > 0) {
          const first = entries[0];
          return { key: String(first[0]), value: String(first[1] ?? '') };
        }
      }
      return null;
    })
    .filter((item): item is SpecificationItem => item !== null);
}

function normalizeReviews(items: unknown[] | undefined): ReviewItem[] {
  if (!items || !Array.isArray(items)) return [];
  return items
    .map((item) => {
      if (!item || typeof item !== 'object') return null;
      const record = item as Record<string, unknown>;
      return {
        author: String(record.author ?? 'Anonymous'),
        rating: Number(record.rating ?? 0),
        text: String(record.text ?? ''),
        date: String(record.date ?? ''),
      };
    })
    .filter((item): item is ReviewItem => item !== null);
}

function formatCurrency(amount: number, currency: string): string {
  const safeAmount = Number.isFinite(amount) ? amount : 0;
  const safeCurrency = currency || '';
  return `${safeCurrency}${safeAmount.toFixed(2)}`;
}

