              </Row>
              <Badge variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'} size="md">
                {isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock'}
              </Badge>
            </Stack>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-5)" border shadow="sm">
          <Tabs items={tabItems} activeKey={activeTab} onChange={setActiveTab} variant="line" />
        </Card>

        <Card padding="var(--ggui-spacing-5)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={4}>Purchase</Heading>
            <Row gap="var(--ggui-spacing-3)" align="center" wrap>
              <Text variant="label">Quantity</Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Button variant="outline" size="sm" onPress={decrement} disabled={quantity <= 1}>
                  −
                </Button>
                <Box padding="var(--ggui-spacing-2)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Text>{quantity}</Text>
                </Box>
                <Button variant="outline" size="sm" onPress={increment} disabled={maxStock <= 0 || quantity >= maxStock}>
                  +
                </Button>
              </Row>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Max: {maxStock}
              </Text>
            </Row>
            <Button variant="primary" onPress={handleAddToCart} disabled={isOutOfStock || !props.product?.id}>
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

