// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Place helper components here if needed

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(props.initialProfile?.avatar ?? (props.avatarOptions[0] ?? '😀'));
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme === 'dark' ? 'dark' : 'light');
  const [showValidation, setShowValidation] = useState<boolean>(false);

  const isNameValid = name.trim().length > 0;
  const isEmailValid = EMAIL_REGEX.test(email.trim());
  const stepOneValid = isNameValid && isEmailValid && avatar.trim().length > 0;
  const stepTwoValid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');
  const canProceed = step === 1 ? stepOneValid : step === 2 ? stepTwoValid : true;
  const progressValue = (step / 3) * 100;

  const avatarChoices = (props.avatarOptions && props.avatarOptions.length >= 4
    ? props.avatarOptions.slice(0, 4)
    : ['😀', '😎', '🚀', '🎨']);

  const roleChoices = (props.roleOptions && props.roleOptions.length > 0
    ? props.roleOptions
    : ['Developer', 'Designer', 'Manager', 'Other']).map((option) => ({
      label: option,
      value: option,
    }));

  useEffect(() => {
    if (step !== 1) {
      setShowValidation(false);
    }
  }, [step]);

  const handleNext = useCallback(() => {
    if (step === 1 && !stepOneValid) {
      setShowValidation(true);
      return;
    }
    if (step < 3) {
      setStep(step + 1);
    }
  }, [step, stepOneValid]);

  const handleBack = useCallback(() => {
    if (step > 1) {
      setStep(step - 1);
    }
  }, [step]);

  const handleComplete = useCallback(() => {
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    if (typeof (props as { onComplete?: (data: ActionCompletePayload) => void }).onComplete === 'function') {
      (props as { onComplete?: (data: ActionCompletePayload) => void }).onComplete?.(payload);
      return;
    }
    complete(payload);
  }, [name, email, avatar, role, emailNotifications, theme, complete, props]);

  const stepTitle = useMemo(() => {
    if (step === 1) return 'Profile Setup';
    if (step === 2) return 'Preferences';
    return 'Review & Confirm';
  }, [step]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Stack gap="var(--ggui-spacing-1)">
                <Heading level={2}>Onboarding Wizard</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">Step {step} of 3 • {stepTitle}</Text>
              </Stack>
              <Badge variant="primary">{Math.round(progressValue)}%</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" variant="default" />
          </Stack>
        </Card>

        <Box
          key={step}
          padding="var(--ggui-spacing-1)"
          style={{ animation: 'ggui-fadeIn 200ms ease-out' } as React.CSSProperties}
        >
          {step === 1 && (
            <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your name"
                  required
                  error={showValidation && !isNameValid ? 'Name is required.' : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="you@example.com"
                  required
                  error={showValidation && !isEmailValid ? 'Enter a valid email address.' : undefined}
                />
                <RadioGroup
                  label="Choose Avatar"
                  value={avatar}
                  onChange={setAvatar}
                  options={avatarChoices.map((emoji) => ({
                    label: `Select avatar ${emoji}`,
                    value: emoji,
                    description: emoji,
                  }))}
                  direction="horizontal"
                />
              </Stack>
            </Card>
          )}

          {step === 2 && (
            <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={roleChoices}
                  placeholder="Select your role"
                  required
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />
                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  size="md"
                />
                <Text color="var(--ggui-color-onSurfaceVariant)">Current theme: {theme}</Text>
              </Stack>
            </Card>
          )}

          {step === 3 && (
            <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Review & Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" shadow="none" radius="md" border>
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Name</Text><Text>{name || '—'}</Text></Row>
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Email</Text><Text>{email || '—'}</Text></Row>
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Avatar</Text><Text>{avatar || '—'}</Text></Row>
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Role</Text><Text>{role || '—'}</Text></Row>
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant)">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            </Card>
          )}
        </Box>

        <Row justify="between" align="center">
          <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {step < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={!canProceed}>
                Next
              </Button>
            ) : (
              <>
                <Button variant="outline" onClick={handleBack}>Go Back</Button>
                <Button variant="primary" onClick={handleComplete} disabled={!stepOneValid || !stepTwoValid}>
                  Complete Setup
                </Button>
              </>
            )}
          </Row>
        </Row>
      </Stack>
    </Container>

  );
}
